45: func (s *store) Read(mode ReadTxMode, trace *traceutil.Trace) TxnRead {
46: 	s.mu.RLock()
47: 	s.revMu.RLock()
48: 	// For read-only workloads, we use shared buffer by copying transaction read buffer
49: 	// for higher concurrency with ongoing blocking writes.
50: 	// For write/write-read transactions, we use the shared buffer
51: 	// rather than duplicating transaction read buffer to avoid transaction overhead.
52: 	var tx backend.ReadTx
53: 	if mode == ConcurrentReadTxMode {
54: 		tx = s.b.ConcurrentReadTx()
55: 	} else {
56: 		tx = s.b.ReadTx()
57: 	}
58: 
59: 	tx.RLock() // RLock is no-op. concurrentReadTx does not need to be locked after it is created.
60: 	firstRev, rev := s.compactMainRev, s.currentRev
61: 	s.revMu.RUnlock()
62: 	return newMetricsTxnRead(&storeTxnRead{storeTxnCommon{s, tx, firstRev, rev, trace}, tx})
63: }
