65: func (tr *storeTxnCommon) FirstRev() int64 { return tr.firstRev }
66: func (tr *storeTxnCommon) Rev() int64      { return tr.rev }
67: 
68: func (tr *storeTxnCommon) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {
69: 	return tr.rangeKeys(ctx, key, end, tr.Rev(), ro)
70: }
