72: func (tr *storeTxnCommon) rangeKeys(ctx context.Context, key, end []byte, curRev int64, ro RangeOptions) (*RangeResult, error) {
73: 	rev := ro.Rev
74: 	if rev > curRev {
75: 		return &RangeResult{KVs: nil, Count: -1, Rev: curRev}, ErrFutureRev
76: 	}
77: 	if rev <= 0 {
78: 		rev = curRev
79: 	}
80: 	if rev < tr.s.compactMainRev {
81: 		return &RangeResult{KVs: nil, Count: -1, Rev: 0}, ErrCompacted
82: 	}
83: 	if ro.Count {
84: 		total := tr.s.kvindex.CountRevisions(key, end, rev)
85: 		tr.trace.Step("count revisions from in-memory index tree")
86: 		return &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil
87: 	}
88: 	revpairs, total := tr.s.kvindex.Revisions(key, end, rev, int(ro.Limit))
89: 	tr.trace.Step("range keys from in-memory index tree")
90: 	if len(revpairs) == 0 {
91: 		return &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil
92: 	}
93: 
94: 	limit := int(ro.Limit)
95: 	if limit <= 0 || limit > len(revpairs) {
96: 		limit = len(revpairs)
97: 	}
98: 
99: 	kvs := make([]mvccpb.KeyValue, limit)
100: 	revBytes := NewRevBytes()
101: 	for i, revpair := range revpairs[:len(kvs)] {
102: 		select {
103: 		case <-ctx.Done():
104: 			return nil, fmt.Errorf("rangeKeys: context cancelled: %w", ctx.Err())
105: 		default:
106: 		}
107: 		revBytes = RevToBytes(revpair, revBytes)
108: 		_, vs := tr.tx.UnsafeRange(schema.Key, revBytes, nil, 0)
109: 		if len(vs) != 1 {
110: 			tr.s.lg.Fatal(
111: 				"range failed to find revision pair",
112: 				zap.Int64("revision-main", revpair.Main),
113: 				zap.Int64("revision-sub", revpair.Sub),
114: 				zap.Int64("revision-current", curRev),
115: 				zap.Int64("range-option-rev", ro.Rev),
116: 				zap.Int64("range-option-limit", ro.Limit),
117: 				zap.Binary("key", key),
118: 				zap.Binary("end", end),
119: 				zap.Int("len-revpairs", len(revpairs)),
120: 				zap.Int("len-values", len(vs)),
121: 			)
122: 		}
123: 		if err := kvs[i].Unmarshal(vs[0]); err != nil {
124: 			tr.s.lg.Fatal(
125: 				"failed to unmarshal mvccpb.KeyValue",
126: 				zap.Error(err),
127: 			)
128: 		}
129: 	}
130: 	tr.trace.Step("range keys from bolt db")
131: 	return &RangeResult{KVs: kvs, Count: total, Rev: curRev}, nil
132: }
