139: type storeTxnWrite struct {
140: 	storeTxnCommon
141: 	tx backend.BatchTx
142: 	// beginRev is the revision where the txn begins; it will write to the next revision.
143: 	beginRev int64
144: 	changes  []mvccpb.KeyValue
145: }
