147: func (s *store) Write(trace *traceutil.Trace) TxnWrite {
148: 	s.mu.RLock()
149: 	tx := s.b.BatchTx()
150: 	tx.LockInsideApply()
151: 	tw := &storeTxnWrite{
152: 		storeTxnCommon: storeTxnCommon{s, tx, 0, 0, trace},
153: 		tx:             tx,
154: 		beginRev:       s.currentRev,
155: 		changes:        make([]mvccpb.KeyValue, 0, 4),
156: 	}
157: 	return newMetricsTxnWrite(tw)
158: }
159: 
160: func (tw *storeTxnWrite) Rev() int64 { return tw.beginRev }
161: 
162: func (tw *storeTxnWrite) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {
163: 	rev := tw.beginRev
164: 	if len(tw.changes) > 0 {
165: 		rev++
166: 	}
167: 	return tw.rangeKeys(ctx, key, end, rev, ro)
168: }
169: 
170: func (tw *storeTxnWrite) DeleteRange(key, end []byte) (int64, int64) {
171: 	if n := tw.deleteRange(key, end); n != 0 || len(tw.changes) > 0 {
172: 		return n, tw.beginRev + 1
173: 	}
174: 	return 0, tw.beginRev
175: }
176: 
177: func (tw *storeTxnWrite) Put(key, value []byte, lease lease.LeaseID) int64 {
178: 	tw.put(key, value, lease)
179: 	return tw.beginRev + 1
180: }
181: 
182: func (tw *storeTxnWrite) End() {
183: 	// only update index if the txn modifies the mvcc state.
184: 	if len(tw.changes) != 0 {
185: 		// hold revMu lock to prevent new read txns from opening until writeback.
186: 		tw.s.revMu.Lock()
187: 		tw.s.currentRev++
188: 	}
189: 	tw.tx.Unlock()
190: 	if len(tw.changes) != 0 {
191: 		tw.s.revMu.Unlock()
192: 	}
193: 	tw.s.mu.RUnlock()
194: }
