196: func (tw *storeTxnWrite) put(key, value []byte, leaseID lease.LeaseID) {
197: 	rev := tw.beginRev + 1
198: 	c := rev
199: 	oldLease := lease.NoLease
200: 
201: 	// if the key exists before, use its previous created and
202: 	// get its previous leaseID
203: 	_, created, ver, err := tw.s.kvindex.Get(key, rev)
204: 	if err == nil {
205: 		c = created.Main
206: 		oldLease = tw.s.le.GetLease(lease.LeaseItem{Key: string(key)})
207: 		tw.trace.Step("get key's previous created_revision and leaseID")
208: 	}
209: 	ibytes := NewRevBytes()
210: 	idxRev := Revision{Main: rev, Sub: int64(len(tw.changes))}
211: 	ibytes = RevToBytes(idxRev, ibytes)
212: 
213: 	ver = ver + 1
214: 	kv := mvccpb.KeyValue{
215: 		Key:            key,
216: 		Value:          value,
217: 		CreateRevision: c,
218: 		ModRevision:    rev,
219: 		Version:        ver,
220: 		Lease:          int64(leaseID),
221: 	}
222: 
223: 	d, err := kv.Marshal()
224: 	if err != nil {
225: 		tw.storeTxnCommon.s.lg.Fatal(
226: 			"failed to marshal mvccpb.KeyValue",
227: 			zap.Error(err),
228: 		)
229: 	}
230: 
231: 	tw.trace.Step("marshal mvccpb.KeyValue")
232: 	tw.tx.UnsafeSeqPut(schema.Key, ibytes, d)
233: 	tw.s.kvindex.Put(key, idxRev)
234: 	tw.changes = append(tw.changes, kv)
235: 	tw.trace.Step("store kv pair into bolt db")
236: 
237: 	if oldLease == leaseID {
238: 		tw.trace.Step("attach lease to kv pair")
239: 		return
240: 	}
241: 
242: 	if oldLease != lease.NoLease {
243: 		if tw.s.le == nil {
244: 			panic("no lessor to detach lease")
245: 		}
246: 		err = tw.s.le.Detach(oldLease, []lease.LeaseItem{{Key: string(key)}})
247: 		if err != nil {
248: 			tw.storeTxnCommon.s.lg.Error(
249: 				"failed to detach old lease from a key",
250: 				zap.Error(err),
251: 			)
252: 		}
253: 	}
254: 	if leaseID != lease.NoLease {
255: 		if tw.s.le == nil {
256: 			panic("no lessor to attach lease")
257: 		}
258: 		err = tw.s.le.Attach(leaseID, []lease.LeaseItem{{Key: string(key)}})
259: 		if err != nil {
260: 			panic("unexpected error from lease Attach")
261: 		}
262: 	}
263: 	tw.trace.Step("attach lease to kv pair")
264: }
265: 
266: func (tw *storeTxnWrite) deleteRange(key, end []byte) int64 {
267: 	rrev := tw.beginRev
268: 	if len(tw.changes) > 0 {
269: 		rrev++
270: 	}
271: 	keys, _ := tw.s.kvindex.Range(key, end, rrev)
272: 	if len(keys) == 0 {
273: 		return 0
274: 	}
275: 	for _, key := range keys {
276: 		tw.delete(key)
277: 	}
278: 	return int64(len(keys))
279: }
280: 
281: func (tw *storeTxnWrite) delete(key []byte) {
282: 	ibytes := NewRevBytes()
283: 	idxRev := newBucketKey(tw.beginRev+1, int64(len(tw.changes)), true)
284: 	ibytes = BucketKeyToBytes(idxRev, ibytes)
285: 
286: 	kv := mvccpb.KeyValue{Key: key}
287: 
288: 	d, err := kv.Marshal()
289: 	if err != nil {
290: 		tw.storeTxnCommon.s.lg.Fatal(
291: 			"failed to marshal mvccpb.KeyValue",
292: 			zap.Error(err),
293: 		)
294: 	}
295: 
296: 	tw.tx.UnsafeSeqPut(schema.Key, ibytes, d)
297: 	err = tw.s.kvindex.Tombstone(key, idxRev.Revision)
298: 	if err != nil {
299: 		tw.storeTxnCommon.s.lg.Fatal(
300: 			"failed to tombstone an existing key",
301: 			zap.String("key", string(key)),
302: 			zap.Error(err),
303: 		)
304: 	}
305: 	tw.changes = append(tw.changes, kv)
306: 
307: 	item := lease.LeaseItem{Key: string(key)}
308: 	leaseID := tw.s.le.GetLease(item)
309: 
310: 	if leaseID != lease.NoLease {
311: 		err = tw.s.le.Detach(leaseID, []lease.LeaseItem{item})
312: 		if err != nil {
313: 			tw.storeTxnCommon.s.lg.Error(
314: 				"failed to detach old lease from a key",
315: 				zap.Error(err),
316: 			)
317: 		}
318: 	}
319: }
320: 
321: func (tw *storeTxnWrite) Changes() []mvccpb.KeyValue { return tw.changes }
